Here is the plan for adding the `mistral-instruct-v3` specialized chat template handler to `common/chat.cpp`. Only that one file needs to be modified.

**Two changes, both in `common/chat.cpp`:**

---

### Change 1 — New handler function (insert before line 1634)

Insert `common_chat_params_init_mistral_instruct_v3` between the closing `}` of `common_chat_extra_context()` and the start of `common_chat_try_specialized_template()`:

```cpp
static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template & tmpl,
        const autoparser::generation_params & inputs) {

    common_chat_params data;

    std::string system_msg;
    std::string prompt;
    bool first_user = true;

    for (const auto & msg : inputs.messages) {
        const auto role    = msg.value("role", "");
        const auto content = msg.value("content", "");

        if (role == "system") {
            system_msg = content;
        } else if (role == "user") {
            if (first_user) {
                if (!system_msg.empty()) {
                    prompt += "<s>[INST] " + system_msg + "\n" + content + " [/INST]";
                } else {
                    prompt += "<s>[INST] " + content + " [/INST]";
                }
                first_user = false;
            } else {
                prompt += "[INST] " + content + " [/INST]";
            }
        } else if (role == "assistant") {
            prompt += " " + content + "</s>";
        }
    }

    data.prompt = prompt;
    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    return data;
}
```

---

### Change 2 — Detection block (insert before `return std::nullopt;` at line 1690)

```cpp
    // Mistral Instruct v3 - uses [INST]...[/INST] turn format without [SYSTEM_PROMPT]
    if (src.find("[INST]") != std::string::npos && src.find("[/INST]") != std::string::npos &&
        src.find("[SYSTEM_PROMPT]") == std::string::npos) {
        LOG_DBG("Using specialized template: Mistral Instruct v3\n");
        return common_chat_params_init_mistral_instruct_v3(tmpl, params);
